module RefModule(accum,data,ena,clk,rst);output [7:0]accum;
input clk,rst,ena;
input [7:0]data;
reg [7:0] accum;
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge dbg_halt)
begin
  if(rst)
    accum<=8'b00000000;
  else
    if(ena)
      accum<=data;
end
endmodule
